CREATE TABLE users (id SERIAL PRIMARY KEY, full_name VARCHAR(180) NOT NULL, email VARCHAR(120) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, role VARCHAR(20) NOT NULL, is_active BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE request_categories (id SERIAL PRIMARY KEY, name VARCHAR(120) NOT NULL, description TEXT, is_active BOOLEAN DEFAULT TRUE);
CREATE TABLE requests (id SERIAL PRIMARY KEY, student_id INTEGER REFERENCES users(id), category_id INTEGER REFERENCES request_categories(id), title VARCHAR(180) NOT NULL, description TEXT NOT NULL, status VARCHAR(40), priority VARCHAR(30), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE request_files (id SERIAL PRIMARY KEY, request_id INTEGER REFERENCES requests(id), file_name VARCHAR(255), file_path VARCHAR(255), uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE request_comments (id SERIAL PRIMARY KEY, request_id INTEGER REFERENCES requests(id), user_id INTEGER REFERENCES users(id), comment_text TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE status_history (id SERIAL PRIMARY KEY, request_id INTEGER REFERENCES requests(id), old_status VARCHAR(40), new_status VARCHAR(40), changed_by INTEGER REFERENCES users(id), changed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE activity_log (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), action VARCHAR(255), entity_type VARCHAR(80), entity_id INTEGER, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
